window.__QUIZ_DATA__=[{"id":"theory>Marketing>2020>1>a","subject":"Marketing","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES","question":"Oliver Ltd, a producer of fruit juice sells its products to stores across the country.    List six advertising media the company could use to create awareness about its products","images":[],"marking_scheme":"- Television  - Radio  - Magazine  - Newspapers  - Product placement  - Internet","marks":"5","difficulty":"2"},{"id":"theory>Marketing>2020>1>b","subject":"Marketing","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ADVERTISING : FUNCTIONS","question":"Oliver Ltd, a producer of fruit juice sells its products to stores across the country.State three benefits the company would derive from advertising the products","images":[],"marking_scheme":"- The revenue/turnover of the company will increase    - Consumers will be aware of the new product feature or price    - To increase market share    -","marks":"5","difficulty":"2"},{"id":"theory>Marketing>2020>1>c","subject":"Marketing","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"TRANSPORTATION : FACTORS AFFECTING CHOICE OF TRANSPORTATION","question":"Oliver Ltd, a producer of fruit juice sells its products to stores across the country.State four factors that would influence the company's choice of mode of transporting its products","images":[],"marking_scheme":"- Cost of service  - Speed of transport  - Nature of commodity  - Regularity of services","marks":"5","difficulty":"2"},{"id":"theory>Marketing>2020>2>a>i","subject":"Marketing","year":"2020","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PRODUCTS : DISTINCTION BETWEEN CLASSES OF PRODUCTS","question":"Distinguish between:    -  primary product and secondary product;","images":[],"marking_scheme":"Primary product is a product that is essential in providing solution to a specific problem customer seeks to resolve while secondary product is a product that is not essential to solving customer's problem.","marks":"5","difficulty":"3"},{"id":"theory>Marketing>2020>2>a>ii","subject":"Marketing","year":"2020","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS ( MEANING, TYPES AND ROLES)","question":"Distinguish between:market facilitator and market union","images":[],"marking_scheme":"Market facilitator is a consultant whose primary function is to stimulate markets while remaining outside of the market themselves while market union refers to various trade who sell similar commodities or product in a particular market.","marks":"5","difficulty":"3"},{"id":"theory>Marketing>2020>2>b","subject":"Marketing","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS ( MEANING, TYPES AND ROLES)","question":"Distinguish between:List four market facilitators and state one function of each in aiding the activities of marketers","images":[],"marking_scheme":"- Advertising agency: These are agents that help to expose the product to the consumers through advertising media such as television,radio etc    - Market research firm: These are agents that gather information about a market's size for the purpose of introducing the products to the customers    - Transportation firm: They help to transport the product to the customers or consumers    - Insurance brokers and agents: They sell the goods or product on behalf of the marketing firm.","marks":"5","difficulty":"3"},{"id":"theory>Marketing>2020>3>a","subject":"Marketing","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTERNATIONAL MARKETING : INFLUENCING FACTORS","question":"Joan Ltd, a product of cosmetic products, has decided to engage in international marketing of its products    -  State five factors that may have influenced Joan Ltd's decision to go international","images":[],"marking_scheme":"- The possibilty of increasing revenue of the company    - The presence of new customers base    - Expansion of the business    - To gain competitive advantage    - Lower operational cost","marks":"7","difficulty":"2"},{"id":"theory>Marketing>2020>3>b","subject":"Marketing","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"INTERNATIONAL MARKETING : GUIDING RULES AND REGULATIONS","question":"Joan Ltd, a product of cosmetic products, has decided to engage in international marketing of its productsState five rules and regulations the company would observe while selling its products in other countries","images":[],"marking_scheme":"- The company must learn all the prohibitions and laws of the country    - The law governing the country advertising    - Promotion mechanics rules and regulation    - Tax system rules and regulation of the country    - Shipping rules and regulation","marks":"8","difficulty":"3"},{"id":"theory>Marketing>2020>4>a","subject":"Marketing","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"MARKETING PLANNING AND RESEARCH : REASONS FOR MARKETING PLANNING AND RESEARCH","question":"Audu Ltd, a trading company,has just set up a committee to conduct a marketing research for the company    - State five reasons that would have necessitated the conduct of the research","images":[],"marking_scheme":"- To Identify the problems areas in the business    - To understand the needs of existing customers    - To identify new business opportunities and changing market trends    - To recognize new areas for expansion and increase customer base    - To discover potential customers and their needs,which can be incorporated into the services.","marks":"8","difficulty":"2"},{"id":"theory>Marketing>2020>4>b","subject":"Marketing","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING","question":"Audu Ltd, a trading company,has just set up a committee to conduct a marketing research for the companyState five steps the committee would take in carrying out the assignment","images":[],"marking_scheme":"- Identifying and defining the problem    - Statement of research objectives    - Planning the research design     - Planning the sample    - Data collection, processing and analysis","marks":"7","difficulty":"3"},{"id":"theory>Marketing>2020>5>a","subject":"Marketing","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ADVERTISING : PRODUCTION OF SAMLE ADVERTS","question":"Use the advert in Figure 1 below to answer the following questions.      List six items that would be found on the package of the product labelled A","images":["data:image/png;base64,"],"marking_scheme":"- Name of the product  - Expiry date  - Ingredients  - Weight  - manufacturer's contact details  - Direction/Instruction for usuage","marks":"5","difficulty":"2"},{"id":"theory>Marketing>2020>5>b","subject":"Marketing","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ADVERTISING : FUNCTIONS","question":"Use the advert in Figure 1 below to answer the following questions.   State three functions of the part labelled B","images":["data:image/png;base64,"],"marking_scheme":"- To give information about the product    - To inform the users about the value of the product    - To build brand preference in the market","marks":"5","difficulty":"2"},{"id":"theory>Marketing>2020>5>c","subject":"Marketing","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES","question":"Use the advert in Figure 1 below to answer the following questions.   State four advantages of using this medium to advertise the product","images":["data:image/png;base64,"],"marking_scheme":"- It offers sight, action and sound benefit to the customer    - It provided recreation to the viewers    - It gives high in-the-room intimacy and can present national coverage on network    - The product is visibly demonstrated to appeal to the target audience.","marks":"5","difficulty":"3"},{"id":"theory>Marketing>2020>6>a","subject":"Marketing","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER","question":"Outline four differences between organizational buying behaviour and consumer buying behaviour","images":[],"marking_scheme":"- The organizations buy goods and services for their business needs while the individual consumers buy goods and services for ultimate use or satisfy their needs    - Organizational buying is done in large quantities while consumer buy various kinds of goods.The quantity of goods remains small.    - Organizational purchasing is a rational process because the purchasing behaviour of organizations is guided by objective factors while consumer buying takes decisions by consumers themselves    - Organizational purchase criteria are specifically defined while consumer may not have adequate knowledge and information about the market situation","marks":"7","difficulty":"3"},{"id":"theory>Marketing>2020>6>b","subject":"Marketing","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS","question":"List and explain three influencing factors in organizational buying behaviour.","images":[],"marking_scheme":"- Economic  factors  - Technological factors  - Political and legal factors    - Economic factors: It includes the level of demand,economic condition,competition,change in technology, trade cycle etc. The change in the general economic conditions of a market affects the demand for organizational products which is related to the demand for consumer products.    Technological factors: Technological factors such as the development of e-commerce,  development of information, development of internet have brought changes in institutional buying and inventory management,production process,distribution management etc    - Political and legal factors: Institutions may be affected by political and legal factors.Every organization has to operate their activities according to the rules and regulation of the nation so while buying goods and services organization should study about the political system,political situation,political ideology,government policies etc.","marks":"8","difficulty":"2"}];